"use client";

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { FadeIn, StaggerContainer, StaggerItem } from '@/components/animations/MotionUtils';
import { apiClient, ApiError } from '@/lib/apiClient';
import { useAuth } from '@/lib/authContext';

interface StudyMaterial {
  id: string;
  title: string;
  fileUrl: string;
  uploadedAt: string;
  course: { title: string };
}

const Skeleton = ({ className = '' }: { className?: string }) => (
  <div className={`animate-pulse bg-white/5 border border-white/5 ${className}`} />
);

export default function MaterialsPage() {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading } = useAuth();

  const [materials, setMaterials] = useState<StudyMaterial[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [activeSubject, setActiveSubject] = useState('All');

  useEffect(() => {
    if (!authLoading && !authUser) router.push('/login');
  }, [authUser, authLoading, router]);

  useEffect(() => {
    if (!authUser) return;
    const fetchMaterials = async () => {
      try {
        const data = await apiClient.get<StudyMaterial[]>('/portal/materials');
        setMaterials(data);
      } catch (err) {
        if (err instanceof ApiError && err.status === 401) router.push('/login');
        else setError('ARCHIVE_COMM_FAILURE: DATA_REPOSITORY_OFFLINE');
      } finally {
        setLoading(false);
      }
    };
    fetchMaterials();
  }, [authUser, router]);

  const subjects = ['All', ...Array.from(new Set(materials.map((m) => m.course.title)))];
  const filtered = activeSubject === 'All'
    ? materials
    : materials.filter((m) => m.course.title === activeSubject);

  if (authLoading || loading) {
    return (
      <div className="space-y-12">
        <Skeleton className="h-4 w-32" />
        <div className="flex gap-4">
          {[1, 2, 3].map((i) => <Skeleton key={i} className="h-10 w-24" />)}
        </div>
        <div className="grid lg:grid-cols-1 gap-4">
          {[1, 2, 3, 4].map((i) => <Skeleton key={i} className="h-24 w-full" />)}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-7xl mx-auto w-full p-24 text-center border border-white/5 bg-white/[0.02]">
        <p className="text-red-500 font-black uppercase tracking-tighter text-2xl">{error}</p>
      </div>
    );
  }

  return (
    <div className="space-y-24 pb-32">
      
      {/* Archive Header */}
      <FadeIn>
        <div className="flex flex-col items-start leading-[0.85]">
          <span className="font-script text-4xl text-[#888888] lowercase mb-8 block">access the</span>
          <h1 className="text-7xl md:text-9xl font-black uppercase tracking-tighter-editorial text-white leading-[0.8]">
             Study <br /> <span className="text-white/20">Materials</span>
          </h1>
          <p className="text-xl text-[#888888] lowercase mt-12 max-w-xl leading-relaxed">
            a curated index of institutional resources and faculty research payloads.
          </p>
        </div>
      </FadeIn>

      {/* Filter Bar */}
      <FadeIn delay={0.1}>
        <div className="flex flex-wrap gap-8 border-b border-white/5 pb-12">
          {subjects.map((sub, i) => (
            <button
              key={i}
              onClick={() => setActiveSubject(sub)}
              className={`text-[10px] font-black uppercase tracking-[0.4em] transition-all duration-500 relative
                ${activeSubject === sub ? 'text-white' : 'text-[#555555] hover:text-white'}
              `}
            >
              {sub}
              {activeSubject === sub && (
                <div className="absolute -bottom-12 left-0 w-full h-px bg-white" />
              )}
            </button>
          ))}
        </div>
      </FadeIn>

      {filtered.length === 0 ? (
        <FadeIn>
          <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#555555]">ARCHIVE_EMPTY: NO_RESOURCES_DETECTED</p>
        </FadeIn>
      ) : (
        <StaggerContainer className="flex flex-col divide-y divide-white/5 border-y border-white/5">
          {filtered.map((mat, idx) => (
            <StaggerItem key={mat.id}>
              <div className="group flex flex-col md:flex-row justify-between items-start md:items-center py-12 px-4 hover:bg-white/[0.01] transition-all duration-500">
                <div className="flex items-center gap-12 mb-6 md:mb-0">
                  <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.2em]">{`FILE_${(idx + 1).toString().padStart(3, '0')}`}</span>
                  <div className="flex flex-col">
                    <h3 className="text-3xl font-black text-white uppercase tracking-tighter group-hover:pl-4 transition-all duration-500">{mat.title}</h3>
                    <div className="flex items-center gap-6 mt-2">
                       <span className="text-[9px] font-bold text-white/40 uppercase tracking-[0.3em] italic">{mat.course.title}</span>
                       <span className="h-px w-8 bg-white/10" />
                       <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.3em]">LOGGED: {new Date(mat.uploadedAt).toLocaleDateString('en-IN').toUpperCase()}</span>
                    </div>
                  </div>
                </div>
                
                <a href={mat.fileUrl} target="_blank" rel="noopener noreferrer" className="w-full md:w-auto">
                   <button className="w-full md:w-auto px-12 py-6 border border-white/10 text-[10px] font-bold uppercase tracking-[0.5em] text-[#888888] hover:bg-white hover:text-black hover:border-white transition-all duration-500">
                     [ DOWNLOAD_PAYLOAD ]
                   </button>
                </a>
              </div>
            </StaggerItem>
          ))}
        </StaggerContainer>
      )}

      <FadeIn delay={0.4} className="mt-8 text-[8px] font-black text-white/10 uppercase tracking-[0.5em] flex justify-between items-center">
        <span>ARCHIVE_RESOURCES_COUNT: {filtered.length} / {materials.length}</span>
        <span>SYSTEM_READY</span>
      </FadeIn>
    </div>
  );
}
